inline ulong LCG_random_int(ulong *seed)
{
	const ulong mask = 0x7fffffffffffffffUL;
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	*seed = (a * (*seed) + c) & mask;
	return *seed;
}

inline double LCG_random_double(ulong *seed)
{
	const double m = 9223372036854775808.0;
	*seed = LCG_random_int(seed);
	return (double)(*seed) / m;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong mask = 0x7fffffffffffffffUL;
	ulong a = 2806196910506780709UL;
	ulong c = 1UL;

	n = n & mask;

	ulong a_new = 1UL;
	ulong c_new = 0UL;

	while(n > 0)
	{
		if(n & 1UL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a *= a;
		n >>= 1;
	}

	return (a_new * seed + c_new) & mask;
}

inline int pick_mat(ulong *seed)
{
	double dist[12];
